import{_ as e,C as n,o as a,c as i,aw as o,b as s,w as t,a as r,E as l,ag as c}from"./chunks/framework.Dq2onT5h.js";const u=JSON.parse('{"title":"Forced Inclusion","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Forced Inclusion | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"guides/advanced/forced-inclusion.md","filePath":"guides/advanced/forced-inclusion.md","lastUpdated":1772446570000}');const d=e({name:"guides/advanced/forced-inclusion.md"},[["render",function(e,u,d,h,p,g){const m=n("Mermaid");return a(),i("div",null,[u[1]||(u[1]=o('<h1 id="forced-inclusion" tabindex="-1">Forced Inclusion <a class="header-anchor" href="#forced-inclusion" aria-label="Permalink to &quot;Forced Inclusion&quot;">​</a></h1><p>Forced inclusion is a censorship-resistance mechanism that allows users to submit transactions directly to the DA layer when the sequencer refuses to include them. This ensures users always have an escape hatch in a single sequencer model.</p><h2 id="how-the-single-sequencer-model-works" tabindex="-1">How the Single Sequencer Model Works <a class="header-anchor" href="#how-the-single-sequencer-model-works" aria-label="Permalink to &quot;How the Single Sequencer Model Works&quot;">​</a></h2><ol><li><p><strong>Transaction Submission:</strong></p><ul><li>Users submit transactions to the execution environment via RPC or other interfaces.</li></ul></li><li><p><strong>Transaction Collection and Ordering:</strong></p><ul><li>The execution environment collects incoming transactions.</li><li>The sequencer requests a batch of transactions from the execution environment to be included in the next block.</li></ul></li><li><p><strong>Block Production:</strong></p><ul><li><strong>Without lazy mode:</strong> the sequencer produces new blocks at fixed intervals.</li><li><strong>With lazy mode:</strong> the sequencer produces a block once either <ul><li>enough transactions are collected</li><li>the lazy-mode block interval elapses More info in the <a href="./../config#lazy-mode-lazy-aggregator">lazy mode configuration guide</a>.</li></ul></li><li>Each block contains a batch of ordered transactions and metadata.</li></ul></li><li><p><strong>Data Availability Posting:</strong></p><ul><li>The sequencer posts the block data to the configured DA layer (e.g., Celestia).</li><li>This ensures that anyone can access the data needed to reconstruct the chain state.</li></ul></li><li><p><strong>State Update:</strong></p><ul><li>The sequencer updates the chain state based on the new block and makes the updated state available to light clients and full nodes.</li></ul></li></ol><h2 id="transaction-flow-diagram" tabindex="-1">Transaction Flow Diagram <a class="header-anchor" href="#transaction-flow-diagram" aria-label="Permalink to &quot;Transaction Flow Diagram&quot;">​</a></h2>',5)),(a(),s(c,null,{default:t(()=>[l(m,{id:"mermaid-106",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20User%0A%20%20%20%20participant%20ExecutionEnv%20as%20Execution%20Environment%0A%20%20%20%20participant%20Sequencer%0A%20%20%20%20participant%20DA%20as%20Data%20Availability%20Layer%0A%0A%20%20%20%20User-%3E%3EExecutionEnv%3A%20Submit%20transaction%0A%20%20%20%20Sequencer-%3E%3EExecutionEnv%3A%20Request%20batch%20for%20block%0A%20%20%20%20ExecutionEnv-%3E%3ESequencer%3A%20Provide%20batch%20of%20transactions%0A%20%20%20%20Sequencer-%3E%3EDA%3A%20Post%20block%20data%0A%20%20%20%20Sequencer-%3E%3EExecutionEnv%3A%20Update%20state%0A%20%20%20%20ExecutionEnv-%3E%3EUser%3A%20State%2Fquery%20response%0A"})]),fallback:t(()=>[...u[0]||(u[0]=[r(" Loading... ",-1)])]),_:1})),u[2]||(u[2]=o('<h2 id="forced-inclusion-1" tabindex="-1">Forced Inclusion <a class="header-anchor" href="#forced-inclusion-1" aria-label="Permalink to &quot;Forced Inclusion&quot;">​</a></h2><p>While the single sequencer controls transaction ordering, the system provides a censorship-resistance mechanism called <strong>forced inclusion</strong>. This ensures users can always include their transactions even if the sequencer refuses to process them.</p><h3 id="how-forced-inclusion-works" tabindex="-1">How Forced Inclusion Works <a class="header-anchor" href="#how-forced-inclusion-works" aria-label="Permalink to &quot;How Forced Inclusion Works&quot;">​</a></h3><ol><li><p><strong>Direct DA Submission:</strong></p><ul><li>Users can submit transactions directly to the DA layer&#39;s forced inclusion namespace</li><li>These transactions bypass the sequencer entirely</li></ul></li><li><p><strong>Epoch-Based Retrieval:</strong></p><ul><li>The sequencer retrieves forced inclusion transactions from the DA layer at epoch boundaries</li><li>Epochs are defined by <code>DAEpochForcedInclusion</code> in the genesis configuration</li></ul></li><li><p><strong>Mandatory Inclusion:</strong></p><ul><li>The sequencer MUST include all forced inclusion transactions from an epoch before the epoch ends</li><li>Full nodes verify that forced inclusion transactions are properly included</li></ul></li><li><p><strong>Smoothing:</strong></p><ul><li>If forced inclusion transactions exceed block size limits (<code>MaxBytes</code>), they can be spread across multiple blocks within the same epoch</li><li>All transactions must be included before moving to the next epoch</li></ul></li></ol><h3 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Epoch [100, 109] (epoch size = 10):</span></span>\n<span class="line"><span>  - User submits tx directly to DA at height 102</span></span>\n<span class="line"><span>  - Sequencer retrieves forced txs at epoch start (height 100)</span></span>\n<span class="line"><span>  - Sequencer includes forced tx in blocks before height 110</span></span></code></pre></div><p>See <a href="./based-sequencing">Based Sequencing</a> for a fully decentralized alternative that relies entirely on forced inclusion.</p><h2 id="detecting-malicious-sequencer-behavior" tabindex="-1">Detecting Malicious Sequencer Behavior <a class="header-anchor" href="#detecting-malicious-sequencer-behavior" aria-label="Permalink to &quot;Detecting Malicious Sequencer Behavior&quot;">​</a></h2><p>Full nodes continuously monitor the sequencer to ensure it follows consensus rules, particularly around forced inclusion:</p><h3 id="censorship-detection" tabindex="-1">Censorship Detection <a class="header-anchor" href="#censorship-detection" aria-label="Permalink to &quot;Censorship Detection&quot;">​</a></h3><p>If a sequencer fails to include forced inclusion transactions past their epoch boundary, full nodes will:</p><ol><li><strong>Detect the violation</strong> - missing transactions from past epochs</li><li><strong>Reject invalid blocks</strong> - do not build on top of censoring blocks</li><li><strong>Log the violation</strong> with transaction hashes and epoch details</li><li><strong>Halt consensus</strong> - the chain cannot progress with a malicious sequencer</li></ol>',12))])}]]);export{u as __pageData,d as default};
